import requests; class RestClient:
 def __init__(self): self.session=requests.Session()
 def get(self,url,**k): return self.session.get(url,**k)
 def post(self,url,**k): return self.session.post(url,**k)
 def put(self,url,**k): return self.session.put(url,**k)
 def delete(self,url,**k): return self.session.delete(url,**k)
